RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances
    auto sensor1 = std::make_shared<RecordingNode>();
    auto sensor2 = std::make_shared<RecordingNode>();

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.addNode(sensor1);
    graph.addNode(sensor2);

    // 4. Set up initial dependency
    graph.addObserver(sensor1, sensor2);

    // 5. Save node state for rollback
    auto savedState = graph.getObservers(sensor2); // Assuming getObservers() exists

    // 6. Replace dependencies transactionally
    // Remove existing observer and add new one
    graph.removeObserver(sensor2, sensor1); // Remove initial dependency

    // Create new sensor for replacement
    auto sensor3 = std::make_shared<RecordingNode>();
    graph.addNode(sensor3);
    graph.addObserver(sensor2, sensor3); // Add new dependency

    // 7. Trigger notification on second sensor
    sensor2->valueChanged(true);

    // 8. Record notification count after second binding
    int countAfterSecondBinding = sensor2->notificationCount();

    // 9. Execute rollback
    // Remove current observer
    graph.removeObserver(sensor2, sensor3);

    // Restore original state
    for (const auto& node : savedState) {
        graph.addObserver(sensor2, node.lock()); // Restore original observers
    }

    // 10. Trigger notification on first sensor
    sensor1->valueChanged(true);

    // 11. Record notification count after rollback
    int countAfterRollback = sensor2->notificationCount();

    // 12. Return notification counts
    return RollbackObservation{countAfterSecondBinding, countAfterRollback};
}

}  // namespace test_reaction
