class IntAtomicImpl {
public:
    explicit IntAtomicImpl(int32_t initial) : m_value(initial), m_lastReportedChange(false) {}

    template <typename F>
    void atomicOperation(F&& op) {
        bool changed = false;
        {
            // Capture by reference to modify the original value
            auto lambda = [this](auto& val, F&& op) -> bool {
                int32_t oldValue = val;
                op(val);
                return oldValue != val;
            };
            changed = std::invoke(lambda, m_value, std::forward<F>(op));
        }
        m_lastReportedChange = changed;
    }

    template <typename F>
    void atomicOperation(F&& op, bool forceNotify) {
        bool changed = false;
        {
            auto lambda = [this](auto& val, F&& op) -> bool {
                int32_t oldValue = val;
                op(val);
                changed = (oldValue != val);
                return changed;
            };
            std::invoke(lambda, m_value, std::forward<F>(op));
        }
        m_lastReportedChange = changed || forceNotify;
    }

    int32_t value() const {
        return m_value;
    }

    bool lastReportedChange() const {
        return m_lastReportedChange;
